        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));

        const addSpy = vi.spyOn(window, 'addEventListener');

        menuBtnOf(actionsOf(results, 'a.txt')).click();

        // Exactly one scroll listener, registered on window with useCapture=true.
        const scrollAdds = addSpy.mock.calls.filter((c) => c[0] === 'scroll');
        expect(scrollAdds).toHaveLength(1);
        expect(scrollAdds[0][1]).toBeTypeOf('function');
        expect(scrollAdds[0][2]).toBe(true);
